/* Livery design token system — replaces Open Props */
@import "./styles/variables/index.css";

/* Fonts */
@import "@fontsource-variable/space-grotesk";
@import "@fontsource-variable/recursive/full.css";

html {
    font-size: 125%; /* 19px — readability bump for desktop use */
}

body {
    font-family: var(--lvr-font-family-body);
}

import { createRoot } from "react-dom/client";
import { MutationCache, QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { ReactQueryDevtoolsPanel } from "@tanstack/react-query-devtools";
import { TanStackDevtools } from "@tanstack/react-devtools";
import { createRouter, RouterProvider } from "@tanstack/react-router";
import { TanStackRouterDevtoolsPanel } from "@tanstack/react-router-devtools";
import { routeTree } from "./routeTree.gen.ts";
import "./index.css";

const queryClient = new QueryClient({
    defaultOptions: {
        mutations: {
            meta: { autoInvalidate: true },
        },
    },
    mutationCache: new MutationCache({
        onSuccess: async (_data, _variables, _context, mutation) => {
            if (!mutation.meta?.autoInvalidate) return;
            if (mutation.options.mutationKey) {
                const mainTopic = mutation.options.mutationKey[0];
                await queryClient.invalidateQueries({ queryKey: [mainTopic] });
            }
        },
    }),
});

const router = createRouter({ routeTree });

declare module "@tanstack/react-router" {
    interface Register {
        router: typeof router;
    }
}

createRoot(document.getElementById("root")!).render(
    <QueryClientProvider client={queryClient}>
        <RouterProvider router={router} />
        <TanStackDevtools
            config={{ hideUntilHover: true }}
            plugins={[
                {
                    name: "TanStack Query",
                    render: <ReactQueryDevtoolsPanel client={queryClient} />,
                },
                {
                    name: "TanStack Router",
                    render: <TanStackRouterDevtoolsPanel router={router} />,
                },
            ]}
        />
    </QueryClientProvider>,
);

@import "./colors.css";
@import "./sizes.css";
@import "./borders.css";
@import "./typography.css";
@import "./easings.css";
@import "./durations.css";
@import "./layers.css";

/* =============================================================
   Livery — Easing tokens
   Mirrors the open-props scale (props.easing.css).
   Reference: https://github.com/argyleink/open-props/blob/main/src/props.easing.css
   ============================================================= */

:root {
    /* Standard (ease out — decelerate into rest) */
    --lvr-ease-1: cubic-bezier(0.25, 0, 0.5, 1);
    --lvr-ease-2: cubic-bezier(0.25, 0, 0.4, 1);
    --lvr-ease-3: cubic-bezier(0.25, 0, 0.3, 1);
    --lvr-ease-4: cubic-bezier(0.25, 0, 0.2, 1);
    --lvr-ease-5: cubic-bezier(0.25, 0, 0.1, 1);

    /* Ease-in (accelerate into action) */
    --lvr-ease-in-1: cubic-bezier(0.25, 0, 1, 1);
    --lvr-ease-in-2: cubic-bezier(0.5, 0, 1, 1);
    --lvr-ease-in-3: cubic-bezier(0.7, 0, 1, 1);
    --lvr-ease-in-4: cubic-bezier(0.9, 0, 1, 1);
    --lvr-ease-in-5: cubic-bezier(1, 0, 1, 1);

    /* Ease-out (decelerate into rest) */
    --lvr-ease-out-1: cubic-bezier(0, 0, 0.75, 1);
    --lvr-ease-out-2: cubic-bezier(0, 0, 0.5, 1);
    --lvr-ease-out-3: cubic-bezier(0, 0, 0.3, 1);
    --lvr-ease-out-4: cubic-bezier(0, 0, 0.1, 1);
    --lvr-ease-out-5: cubic-bezier(0, 0, 0.05, 1);
}

/* =============================================================
   Livery — Color tokens
   Naming: --lvr-color-{bg|fg}-{name}
   All color derivation is native CSS — no JS color library.

   Chrome defaults are warm monochrome (DESIGN.md: "Dark warm grays
   on dark mode, warm off-whites on light mode"). ThemeProvider
   overrides these at runtime with @black-atom/core theme values.
   ============================================================= */

/* Seed color-scheme so light-dark() resolves before provider JS runs. */
:root {
    color-scheme: light dark;
}

[data-lvr-color-scheme="dark"] {
    color-scheme: dark;
}

[data-lvr-color-scheme="light"] {
    color-scheme: light;
}

/* =============================================================
   Knobs
   The 80/20 consumer surface. Override -hue or -chroma and the
   token's bg/fg derive accordingly.
   ============================================================= */

:root {
    /* Surfaces — warm gray defaults (low chroma, warm hue ~30) */
    --lvr-color-default-hue: 30;
    --lvr-color-default-chroma: 0.005;

    --lvr-color-subtle-hue: 30;
    --lvr-color-subtle-chroma: 0.005;

    --lvr-color-hint-hue: 30;
    --lvr-color-hint-chroma: 0.005;

    /* Intents */
    --lvr-color-accent-hue: 145;
    --lvr-color-accent-chroma: 0.13;

    --lvr-color-positive-hue: 145;
    --lvr-color-positive-chroma: 0.18;

    --lvr-color-negative-hue: 25;
    --lvr-color-negative-chroma: 0.2;

    --lvr-color-warn-hue: 65;
    --lvr-color-warn-chroma: 0.16;

    --lvr-color-info-hue: 220;
    --lvr-color-info-chroma: 0.12;
}

/* =============================================================
   Semantic tokens
   Components consume these. bg / fg for surfaces and intents.
   ============================================================= */

:root {
    /* ======================= Backgrounds ======================= */
    --lvr-color-bg-default: light-dark(
        oklch(0.95 var(--lvr-color-default-chroma) var(--lvr-color-default-hue)),
        oklch(0.18 var(--lvr-color-default-chroma) var(--lvr-color-default-hue))
    );

    --lvr-color-bg-subtle: light-dark(
        oklch(0.9 var(--lvr-color-subtle-chroma) var(--lvr-color-subtle-hue)),
        oklch(0.22 var(--lvr-color-subtle-chroma) var(--lvr-color-subtle-hue))
    );

    --lvr-color-bg-hint: light-dark(
        oklch(0.85 var(--lvr-color-hint-chroma) var(--lvr-color-hint-hue)),
        oklch(0.28 var(--lvr-color-hint-chroma) var(--lvr-color-hint-hue))
    );

    --lvr-color-bg-accent: light-dark(
        oklch(0.65 var(--lvr-color-accent-chroma) var(--lvr-color-accent-hue)),
        oklch(0.65 var(--lvr-color-accent-chroma) var(--lvr-color-accent-hue))
    );

    --lvr-color-bg-contrast: light-dark(
        oklch(0.15 var(--lvr-color-default-chroma) var(--lvr-color-default-hue)),
        oklch(0.95 var(--lvr-color-default-chroma) var(--lvr-color-default-hue))
    );

    --lvr-color-bg-disabled: light-dark(
        oklch(0.85 var(--lvr-color-default-chroma) var(--lvr-color-default-hue)),
        oklch(0.25 var(--lvr-color-default-chroma) var(--lvr-color-default-hue))
    );

    --lvr-color-bg-positive: light-dark(
        oklch(0.65 var(--lvr-color-positive-chroma) var(--lvr-color-positive-hue)),
        oklch(0.45 var(--lvr-color-positive-chroma) var(--lvr-color-positive-hue))
    );

    --lvr-color-bg-negative: light-dark(
        oklch(0.65 var(--lvr-color-negative-chroma) var(--lvr-color-negative-hue)),
        oklch(0.45 var(--lvr-color-negative-chroma) var(--lvr-color-negative-hue))
    );

    --lvr-color-bg-warn: light-dark(
        oklch(0.65 var(--lvr-color-warn-chroma) var(--lvr-color-warn-hue)),
        oklch(0.45 var(--lvr-color-warn-chroma) var(--lvr-color-warn-hue))
    );

    --lvr-color-bg-info: light-dark(
        oklch(0.65 var(--lvr-color-info-chroma) var(--lvr-color-info-hue)),
        oklch(0.45 var(--lvr-color-info-chroma) var(--lvr-color-info-hue))
    );

    /* ======================= Foregrounds ======================= */

    --lvr-color-fg-default: light-dark(
        oklch(0.15 var(--lvr-color-default-chroma) var(--lvr-color-default-hue)),
        oklch(0.95 var(--lvr-color-default-chroma) var(--lvr-color-default-hue))
    );

    --lvr-color-fg-subtle: color-mix(in oklch, var(--lvr-color-fg-default) 80%, transparent);

    --lvr-color-fg-hint: color-mix(in oklch, var(--lvr-color-fg-default) 60%, transparent);

    --lvr-color-fg-contrast: light-dark(
        oklch(0.95 var(--lvr-color-default-chroma) var(--lvr-color-default-hue)),
        oklch(0.15 var(--lvr-color-default-chroma) var(--lvr-color-default-hue))
    );

    --lvr-color-fg-disabled: color-mix(in oklch, var(--lvr-color-fg-default) 40%, transparent);

    --lvr-color-fg-accent: light-dark(
        oklch(0.55 var(--lvr-color-accent-chroma) var(--lvr-color-accent-hue)),
        oklch(0.65 var(--lvr-color-accent-chroma) var(--lvr-color-accent-hue))
    );

    --lvr-color-fg-positive: light-dark(
        oklch(0.55 var(--lvr-color-positive-chroma) var(--lvr-color-positive-hue)),
        oklch(0.65 var(--lvr-color-positive-chroma) var(--lvr-color-positive-hue))
    );

    --lvr-color-fg-negative: light-dark(
        oklch(0.55 var(--lvr-color-negative-chroma) var(--lvr-color-negative-hue)),
        oklch(0.65 var(--lvr-color-negative-chroma) var(--lvr-color-negative-hue))
    );

    --lvr-color-fg-warn: light-dark(
        oklch(0.55 var(--lvr-color-warn-chroma) var(--lvr-color-warn-hue)),
        oklch(0.65 var(--lvr-color-warn-chroma) var(--lvr-color-warn-hue))
    );

    --lvr-color-fg-info: light-dark(
        oklch(0.55 var(--lvr-color-info-chroma) var(--lvr-color-info-hue)),
        oklch(0.65 var(--lvr-color-info-chroma) var(--lvr-color-info-hue))
    );
}

/* =============================================================
   Shadows
   Adapted from open-props (props.shadows.css) — oklch + color-mix.
   Six elevation levels plus inner shadow variants.
   ============================================================= */

:root {
    --lvr-shadow-color: oklch(0.15 0.01 265);
    --lvr-shadow-strength: 1%;
    --lvr-shadow-strength-3: calc(var(--lvr-shadow-strength) + 2%);
    --lvr-shadow-strength-4: calc(var(--lvr-shadow-strength) + 3%);
    --lvr-shadow-strength-5: calc(var(--lvr-shadow-strength) + 4%);
    --lvr-shadow-strength-6: calc(var(--lvr-shadow-strength) + 5%);
    --lvr-shadow-strength-7: calc(var(--lvr-shadow-strength) + 6%);
    --lvr-shadow-strength-8: calc(var(--lvr-shadow-strength) + 7%);
    --lvr-shadow-strength-10: calc(var(--lvr-shadow-strength) + 9%);
    --lvr-inner-shadow-highlight: inset 0 -0.5px 0 0 #fff, inset 0 0.5px 0 0 #0001;

    --lvr-shadow-1: 0 1px 2px -1px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-10),
        transparent
    );
    --lvr-shadow-2:
        0 3px 5px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-4),
        transparent
    ),
        0 7px 14px -5px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-6),
        transparent
    );
    --lvr-shadow-3:
        0 -1px 3px 0 color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-3),
        transparent
    ),
        0 1px 2px -5px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-3),
        transparent
    ),
        0 2px 5px -5px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-5),
        transparent
    ),
        0 4px 12px -5px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-6),
        transparent
    ),
        0 12px 15px -5px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-8),
        transparent
    );
    --lvr-shadow-4:
        0 -2px 5px 0 color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-3),
        transparent
    ),
        0 1px 1px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-4),
        transparent
    ),
        0 2px 2px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-4),
        transparent
    ),
        0 5px 5px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-5),
        transparent
    ),
        0 9px 9px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-6),
        transparent
    ),
        0 16px 16px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-7),
        transparent
    );
    --lvr-shadow-5:
        0 -1px 2px 0 color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-3),
        transparent
    ),
        0 2px 1px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-4),
        transparent
    ),
        0 5px 5px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-4),
        transparent
    ),
        0 10px 10px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-5),
        transparent
    ),
        0 20px 20px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-6),
        transparent
    ),
        0 40px 40px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-8),
        transparent
    );
    --lvr-shadow-6:
        0 -1px 2px 0 color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-3),
        transparent
    ),
        0 3px 2px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-4),
        transparent
    ),
        0 7px 5px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-4),
        transparent
    ),
        0 12px 10px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-5),
        transparent
    ),
        0 22px 18px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-6),
        transparent
    ),
        0 41px 33px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-7),
        transparent
    ),
        0 100px 80px -2px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-8),
        transparent
    );

    --lvr-inner-shadow-0: inset 0 0 0 1px color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-10),
        transparent
    );
    --lvr-inner-shadow-1:
        inset 0 1px 2px 0 color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-10),
        transparent
    ),
        var(--lvr-inner-shadow-highlight);
    --lvr-inner-shadow-2:
        inset 0 1px 4px 0 color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-10),
        transparent
    ),
        var(--lvr-inner-shadow-highlight);
    --lvr-inner-shadow-3:
        inset 0 2px 8px 0 color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-10),
        transparent
    ),
        var(--lvr-inner-shadow-highlight);
    --lvr-inner-shadow-4:
        inset 0 2px 14px 0 color-mix(
        in oklch,
        var(--lvr-shadow-color) var(--lvr-shadow-strength-10),
        transparent
    ),
        var(--lvr-inner-shadow-highlight);
}

@media (prefers-color-scheme: dark) {
    :root:not([data-lvr-color-scheme="light"]) {
        --lvr-shadow-strength: 25%;
        --lvr-inner-shadow-highlight: inset 0 -0.5px 0 0 #fff1, inset 0 0.5px 0 0 #0007;
    }
}

[data-lvr-color-scheme="dark"] {
    --lvr-shadow-strength: 25%;
    --lvr-inner-shadow-highlight: inset 0 -0.5px 0 0 #fff1, inset 0 0.5px 0 0 #0007;
}

/* =============================================================
   Livery — Typography tokens
   Font-family knobs, weight / size / line-height / letter-spacing
   from the open-props scale.
   Reference: https://github.com/argyleink/open-props/blob/main/src/props.fonts.css
   ============================================================= */

:root {
    /* Base families — brand typefaces */
    --lvr-font-family-sans: "Recursive Variable", sans-serif;
    --lvr-font-family-mono: "Recursive Variable", monospace;

    /* Semantic aliases — Typography components consume these. */
    --lvr-font-family-heading: "Space Grotesk Variable", sans-serif;
    --lvr-font-family-body: var(--lvr-font-family-sans);
    --lvr-font-family-ui: var(--lvr-font-family-sans);
    --lvr-font-family-code: var(--lvr-font-family-mono);

    /* Weights — numeric 1–9 (100–900) */
    --lvr-font-weight-1: 100;
    --lvr-font-weight-2: 200;
    --lvr-font-weight-3: 300;
    --lvr-font-weight-4: 400;
    --lvr-font-weight-5: 500;
    --lvr-font-weight-6: 600;
    --lvr-font-weight-7: 700;
    --lvr-font-weight-8: 800;
    --lvr-font-weight-9: 900;

    /* Sizes — open-props scale (00 through 8) + fluid clamps for headings */
    --lvr-font-size-00: 0.5rem;
    --lvr-font-size-0: 0.75rem;
    --lvr-font-size-1: 1rem;
    --lvr-font-size-2: 1.1rem;
    --lvr-font-size-3: 1.25rem;
    --lvr-font-size-4: 1.5rem;
    --lvr-font-size-5: 2rem;
    --lvr-font-size-6: 2.5rem;
    --lvr-font-size-7: 3rem;
    --lvr-font-size-8: 3.5rem;
    --lvr-font-size-fluid-1: clamp(1rem, 4vw, 1.5rem);
    --lvr-font-size-fluid-2: clamp(1.5rem, 6vw, 2.5rem);
    --lvr-font-size-fluid-3: clamp(2rem, 9vw, 3.5rem);

    /* Line heights — 00 (tight headings) through 5 (loose prose) */
    --lvr-font-lineheight-00: 0.95;
    --lvr-font-lineheight-0: 1.1;
    --lvr-font-lineheight-1: 1.25;
    --lvr-font-lineheight-2: 1.375;
    --lvr-font-lineheight-3: 1.5;
    --lvr-font-lineheight-4: 1.75;
    --lvr-font-lineheight-5: 2;

    /* Letter spacing */
    --lvr-font-letterspacing-tight: -0.025em;
    --lvr-font-letterspacing-normal: 0em;
    --lvr-font-letterspacing-wide: 0.06em;
}

import type { ReactNode } from "react";
import styles from "./app-shell.module.css";

interface AppShellProps {
    /** Slot rendered in the top header bar. */
    header?: ReactNode;
    /** Slot rendered above the footer for progress indication. */
    progress?: ReactNode;
    /** Slot rendered in the bottom footer bar. */
    footer?: ReactNode;
    /** Main content area. */
    children: ReactNode;
}

/**
 * App.Shell — Outer application chrome.
 *
 * Composes header, main content, progress bar, and footer into a full-height
 * flex column with 1px borders between sections. All styling lives in the
 * CSS module; routes that use this component carry zero direct styles.
 */
export function AppShell({ header, progress, footer, children }: AppShellProps) {
    return (
        <div className={styles.root}>
            {header && <header className={styles.header}>{header}</header>}
            <main className={styles.main}>{children}</main>
            {progress && <div className={styles.progress}>{progress}</div>}
            {footer && <footer className={styles.footer}>{footer}</footer>}
        </div>
    );
}

import { createRootRoute, Outlet } from "@tanstack/react-router";
import styles from "./__root.module.css";

export const Route = createRootRoute({
    component: RootLayout,
});

function RootLayout() {
    return (
        <div className={styles.root}>
            <Outlet />
        </div>
    );
}

import { createFileRoute, Outlet } from "@tanstack/react-router";
import { useStore } from "@tanstack/react-store";
import denoConfig from "../../../deno.json" with { type: "json" };
import { AppHeader } from "../../components/app-header.tsx";
import { AppFooter } from "../../components/app-footer.tsx";
import { ProgressBar } from "../../components/progress-bar.tsx";
import { themeToStyleSheet } from "../../lib/tokens.ts";
import { appStore } from "../../store/app.ts";
import { App } from "../../components/layouts/app.ts";

export const Route = createFileRoute("/_app")({
    component: AppLayout,
});

function AppLayout() {
    const updaterResults = useStore(appStore, (s) => s.updaterResults);
    const currentTheme = useStore(appStore, (s) => s.currentTheme);

    return (
        <>
            <style id="black-atom-theme-tokens">{themeToStyleSheet(currentTheme)}</style>
            <App.Shell
                header={<AppHeader version={denoConfig.version} />}
                progress={<ProgressBar results={updaterResults} />}
                footer={<AppFooter />}
            >
                <Outlet />
            </App.Shell>
        </>
    );
}

import { ChevronRight, Moon, Sun } from "lucide-react";
import { cva } from "cva";
import type { ThemeGroup } from "../lib/themes.ts";
import styles from "./theme-list.module.css";

const itemVariants = cva({
    base: styles.item,
    variants: {
        selected: {
            true: styles.selected,
        },
    },
});

interface ThemeListProps {
    groups: ThemeGroup[];
    selectedIndex: number;
    onSelect: (index: number) => void;
}

export function ThemeList({ groups, selectedIndex, onSelect }: ThemeListProps) {
    let flatIndex = 0;

    return (
        <div data-component="theme-list">
            {groups.map((group) => {
                const items = group.themes.map((entry) => {
                    const index = flatIndex++;
                    const isSelected = index === selectedIndex;
                    const name = entry.meta.name;
                    const AppearanceIcon = entry.meta.appearance === "dark" ? Moon : Sun;

                    return (
                        <button
                            key={entry.meta.key}
                            ref={isSelected
                                ? (el) => el?.scrollIntoView({ block: "nearest" })
                                : undefined}
                            type="button"
                            onClick={() => onSelect(index)}
                            className={itemVariants({ selected: isSelected })}
                        >
                            <span className={styles.cursor}>
                                {isSelected && <ChevronRight size={14} />}
                            </span>
                            {name}
                            <span className={styles.icon}>
                                <AppearanceIcon size={12} />
                            </span>
                        </button>
                    );
                });

                return (
                    <div key={group.collectionKey} className={styles.group}>
                        <div className={styles.groupLabel}>
                            {group.label} ({group.themes.length})
                        </div>
                        {items}
                    </div>
                );
            })}
        </div>
    );
}

import styles from "./app-header.module.css";

interface AppHeaderProps {
