/* =============================================================
   SectionHeader — Uppercase mono label with horizontal rule
   DESIGN.md: "Section Headers" pattern.
   ============================================================= */

.root {
    display: flex;
    flex-direction: column;
    gap: var(--lvr-size-1);
    margin-bottom: var(--lvr-size-3);
}

.row {
    display: flex;
    justify-content: space-between;
    align-items: baseline;
}

.label {
    font-family: var(--lvr-font-family-mono);
    font-variation-settings: "MONO" 1;
    font-size: 10px;
    font-weight: var(--lvr-font-weight-5);
    text-transform: uppercase;
    letter-spacing: var(--lvr-font-letterspacing-wide);
    color: var(--lvr-color-fg-subtle);
}

.meta {
    font-family: var(--lvr-font-family-mono);
    font-variation-settings: "MONO" 1;
    font-size: 10px;
    color: var(--lvr-color-fg-hint);
}

.rule {
    border: none;
    border-top: var(--lvr-border-size-1) solid var(--lvr-color-bg-hint);
    margin: 0;
}

.group {
    margin-bottom: var(--lvr-size-2);
}

.groupLabel {
    padding: var(--lvr-size-1) var(--lvr-size-3);
    font-family: var(--lvr-font-family-ui);
    font-size: var(--lvr-font-size-00);
    font-weight: var(--lvr-font-weight-5);
    color: var(--lvr-color-fg-disabled);
    text-transform: uppercase;
    letter-spacing: var(--lvr-font-letterspacing-wide);
}

.item {
    display: flex;
    align-items: center;
    width: 100%;
    text-align: left;
    padding: var(--lvr-size-1) var(--lvr-size-3);
    font-size: var(--lvr-font-size-0);
    cursor: pointer;
    border: none;
    background: transparent;
    font-family: inherit;
    color: var(--lvr-color-fg-subtle);
}

.item:hover {
    color: var(--lvr-color-fg-default);
}

.selected {
    background-color: var(--lvr-color-bg-accent);
    color: var(--lvr-color-fg-default);
}

.cursor {
    display: inline-flex;
    align-items: center;
    width: 14px;
    margin-right: var(--lvr-size-1);
    color: var(--lvr-color-fg-accent);
    flex-shrink: 0;
}

.icon {
    display: inline-flex;
    align-items: center;
    margin-left: auto;
    color: var(--lvr-color-fg-disabled);
    flex-shrink: 0;
}

.selected .icon {
    color: var(--lvr-color-fg-accent);
}

