/* =============================================================
   ThemeDetail — Datasheet card for selected theme
   DESIGN.md: Data Panels / Cards pattern — 1px border, squared
   corners, uppercase mono metadata rows.
   ============================================================= */

.empty {
    color: var(--lvr-color-fg-hint);
    font-size: var(--lvr-font-size-0);
    font-family: var(--lvr-font-family-mono);
    font-variation-settings: "MONO" 1;
}

.card {
    border: var(--lvr-border-size-1) solid var(--lvr-color-bg-hint);
    padding: var(--lvr-size-4);
}

.header {
    display: flex;
    align-items: baseline;
    gap: var(--lvr-size-3);
    margin-bottom: var(--lvr-size-1);
}

.meta {
    margin-top: var(--lvr-size-5);
    display: flex;
    flex-direction: column;
    gap: var(--lvr-size-2);
}

.metaRow {
    display: flex;
    gap: var(--lvr-size-3);
    font-family: var(--lvr-font-family-mono);
    font-variation-settings: "MONO" 1;
    font-size: var(--lvr-font-size-00);
}

.metaLabel {
